import { useState, useCallback, useMemo } from 'react';
import { Racquet, PerformanceCategory, PERFORMANCE_CATEGORIES } from '../types';

export interface ComparisonState {
  selectedRacquets: Racquet[];
  isComparing: boolean;
  maxComparisons: number;
}

export interface ComparisonActions {
  addRacquet: (racquet: Racquet) => void;
  removeRacquet: (racquetId: string) => void;
  clearComparison: () => void;
  toggleComparison: () => void;
  canAddMore: boolean;
  isSelected: (racquetId: string) => boolean;
  exportComparison: () => void;
}

export interface ComparisonData {
  categories: PerformanceCategory[];
  maxValues: Record<PerformanceCategory, number>;
  minValues: Record<PerformanceCategory, number>;
  normalizedData: Array<{
    racquet: Racquet;
    values: Record<PerformanceCategory, number>;
  }>;
}

const MAX_COMPARISONS = 4;

export function useRacquetComparison() {
  const [selectedRacquets, setSelectedRacquets] = useState<Racquet[]>([]);
  const [isComparing, setIsComparing] = useState(false);

  const addRacquet = useCallback((racquet: Racquet) => {
    setSelectedRacquets(prev => {
      if (prev.length >= MAX_COMPARISONS) return prev;
      if (prev.find(r => r.id === racquet.id)) return prev;
      return [...prev, racquet];
    });
  }, []);

  const removeRacquet = useCallback((racquetId: string) => {
    setSelectedRacquets(prev => prev.filter(r => r.id !== racquetId));
  }, []);

  const clearComparison = useCallback(() => {
    setSelectedRacquets([]);
    setIsComparing(false);
  }, []);

  const toggleComparison = useCallback(() => {
    setIsComparing(prev => !prev);
  }, []);

  const canAddMore = selectedRacquets.length < MAX_COMPARISONS;

  const isSelected = useCallback((racquetId: string) => {
    return selectedRacquets.some(r => r.id === racquetId);
  }, [selectedRacquets]);

  const exportComparison = useCallback(() => {
    if (selectedRacquets.length === 0) return;

    const data = selectedRacquets.map(racquet => ({
      model: racquet.model,
      brand: racquet.brand,
      weight_oz: racquet.weight_oz,
      head_size_sq_in: racquet.head_size_sq_in,
      balance_pts: racquet.balance_pts,
      swingweight: racquet.swingweight,
      power_avg: racquet.power_avg,
      control_avg: racquet.control_avg,
      comfort_avg: racquet.comfort_avg,
      maneuverability_avg: racquet.maneuverability_avg,
      stability_avg: racquet.stability_avg,
      overall_avg: racquet.overall_avg,
    }));

    const csv = [
      Object.keys(data[0]).join(','),
      ...data.map(row => Object.values(row).join(','))
    ].join('\n');

    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `racquet-comparison-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  }, [selectedRacquets]);

  const comparisonData = useMemo((): ComparisonData => {
    if (selectedRacquets.length === 0) {
      return {
        categories: [],
        maxValues: {} as Record<PerformanceCategory, number>,
        minValues: {} as Record<PerformanceCategory, number>,
        normalizedData: []
      };
    }

    const categories = PERFORMANCE_CATEGORIES.filter(cat => {
      const avgKey = `${cat.toLowerCase().replace(/\//g, '_')}_avg` as keyof Racquet;
      return selectedRacquets.some(r => r[avgKey] !== undefined);
    });

    const maxValues = {} as Record<PerformanceCategory, number>;
    const minValues = {} as Record<PerformanceCategory, number>;

    categories.forEach(category => {
      const avgKey = `${category.toLowerCase().replace(/\//g, '_')}_avg` as keyof Racquet;
      const values = selectedRacquets
        .map(r => r[avgKey] as number)
        .filter(v => v !== undefined);

      if (values.length > 0) {
        maxValues[category] = Math.max(...values);
        minValues[category] = Math.min(...values);
      }
    });

    const normalizedData = selectedRacquets.map(racquet => {
      const values = {} as Record<PerformanceCategory, number>;

      categories.forEach(category => {
        const avgKey = `${category.toLowerCase().replace(/\//g, '_')}_avg` as keyof Racquet;
        const value = racquet[avgKey] as number;

        if (value !== undefined) {
          const max = maxValues[category];
          const min = minValues[category];
          values[category] = max === min ? 1 : (value - min) / (max - min);
        } else {
          values[category] = 0;
        }
      });

      return { racquet, values };
    });

    return {
      categories,
      maxValues,
      minValues,
      normalizedData
    };
  }, [selectedRacquets]);

  const state: ComparisonState = {
    selectedRacquets,
    isComparing,
    maxComparisons: MAX_COMPARISONS
  };

  const actions: ComparisonActions = {
    addRacquet,
    removeRacquet,
    clearComparison,
    toggleComparison,
    canAddMore,
    isSelected,
    exportComparison
  };

  return {
    ...state,
    ...actions,
    comparisonData
  };
}

