'use client';

import React, { useRef, useEffect } from 'react';
import { Racquet, PerformanceCategory } from '../../lib/types';

interface RadarChartProps {
  racquets: Racquet[];
  categories: PerformanceCategory[];
  normalizedData: Array<{
    racquet: Racquet;
    values: Record<PerformanceCategory, number>;
  }>;
  className?: string;
}

const COLORS = [
  '#3b82f6', // blue
  '#ef4444', // red
  '#10b981', // green
  '#f59e0b', // yellow
];

export function RadarChart({ racquets, categories, normalizedData, className = '' }: RadarChartProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const size = 300;
  const center = size / 2;
  const radius = center - 60;

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Clear canvas
    ctx.clearRect(0, 0, size, size);

    // Draw radar grid
    drawRadarGrid(ctx, center, radius, categories.length);

    // Draw category labels
    drawCategoryLabels(ctx, center, radius, categories);

    // Draw radar lines for each racquet
    normalizedData.forEach((data, index) => {
      const color = COLORS[index % COLORS.length];
      drawRadarLine(ctx, center, radius, data.values, categories, color);
    });
  }, [racquets, categories, normalizedData]);

  const drawRadarGrid = (ctx: CanvasRenderingContext2D, center: number, radius: number, numCategories: number) => {
    ctx.strokeStyle = '#e5e7eb';
    ctx.lineWidth = 1;

    // Draw concentric circles
    for (let i = 1; i <= 5; i++) {
      const r = (radius * i) / 5;
      ctx.beginPath();
      ctx.arc(center, center, r, 0, 2 * Math.PI);
      ctx.stroke();
    }

    // Draw radial lines
    for (let i = 0; i < numCategories; i++) {
      const angle = (i * 2 * Math.PI) / numCategories - Math.PI / 2;
      const x = center + Math.cos(angle) * radius;
      const y = center + Math.sin(angle) * radius;

      ctx.beginPath();
      ctx.moveTo(center, center);
      ctx.lineTo(x, y);
      ctx.stroke();
    }
  };

  const drawCategoryLabels = (ctx: CanvasRenderingContext2D, center: number, radius: number, categories: PerformanceCategory[]) => {
    ctx.fillStyle = '#374151';
    ctx.font = '12px sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    categories.forEach((category, index) => {
      const angle = (index * 2 * Math.PI) / categories.length - Math.PI / 2;
      const x = center + Math.cos(angle) * (radius + 30);
      const y = center + Math.sin(angle) * (radius + 30);

      // Adjust text alignment based on position
      if (x < center - 10) {
        ctx.textAlign = 'right';
      } else if (x > center + 10) {
        ctx.textAlign = 'left';
      } else {
        ctx.textAlign = 'center';
      }

      ctx.fillText(category, x, y);
    });
  };

  const drawRadarLine = (
    ctx: CanvasRenderingContext2D,
    center: number,
    radius: number,
    values: Record<PerformanceCategory, number>,
    categories: PerformanceCategory[],
    color: string
  ) => {
    if (categories.length === 0) return;

    ctx.strokeStyle = color;
    ctx.fillStyle = color + '20'; // Add transparency
    ctx.lineWidth = 2;

    // Draw filled area
    ctx.beginPath();
    categories.forEach((category, index) => {
      const value = values[category] || 0;
      const angle = (index * 2 * Math.PI) / categories.length - Math.PI / 2;
      const x = center + Math.cos(angle) * (radius * value);
      const y = center + Math.sin(angle) * (radius * value);

      if (index === 0) {
        ctx.moveTo(x, y);
      } else {
        ctx.lineTo(x, y);
      }
    });
    ctx.closePath();
    ctx.fill();

    // Draw outline
    ctx.beginPath();
    categories.forEach((category, index) => {
      const value = values[category] || 0;
      const angle = (index * 2 * Math.PI) / categories.length - Math.PI / 2;
      const x = center + Math.cos(angle) * (radius * value);
      const y = center + Math.sin(angle) * (radius * value);

      if (index === 0) {
        ctx.moveTo(x, y);
      } else {
        ctx.lineTo(x, y);
      }
    });
    ctx.closePath();
    ctx.stroke();

    // Draw data points
    ctx.fillStyle = color;
    categories.forEach((category, index) => {
      const value = values[category] || 0;
      const angle = (index * 2 * Math.PI) / categories.length - Math.PI / 2;
      const x = center + Math.cos(angle) * (radius * value);
      const y = center + Math.sin(angle) * (radius * value);

      ctx.beginPath();
      ctx.arc(x, y, 3, 0, 2 * Math.PI);
      ctx.fill();
    });
  };

  return (
    <div className={`flex flex-col items-center ${className}`}>
      <canvas
        ref={canvasRef}
        width={size}
        height={size}
        className="border border-gray-200 rounded-lg bg-white"
      />

      {/* Legend */}
      <div className="flex flex-wrap justify-center gap-4 mt-4">
        {racquets.map((racquet, index) => (
          <div key={racquet.id} className="flex items-center gap-2">
            <div
              className="w-4 h-4 rounded-full"
              style={{ backgroundColor: COLORS[index % COLORS.length] }}
            />
            <span className="text-sm text-gray-700">
              {racquet.brand} {racquet.model}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

