'use client';

import React from 'react';
import { Racquet } from '../../lib/types';

interface ComparisonTableProps {
  racquets: Racquet[];
  className?: string;
}

interface ComparisonRow {
  label: string;
  key: keyof Racquet;
  format?: (value: any) => string;
  category: 'basic' | 'physical' | 'performance';
}

const COMPARISON_ROWS: ComparisonRow[] = [
  // Basic Info
  { label: 'Brand', key: 'brand', category: 'basic' },
  { label: 'Model', key: 'model', category: 'basic' },
  { label: 'Review Count', key: 'review_count', format: (v) => v?.toString() || 'N/A', category: 'basic' },

  // Physical Specs
  { label: 'Weight (oz)', key: 'weight_oz', format: (v) => v ? `${v} oz` : 'N/A', category: 'physical' },
  { label: 'Head Size (sq in)', key: 'head_size_sq_in', format: (v) => v ? `${v} sq in` : 'N/A', category: 'physical' },
  { label: 'Length (in)', key: 'length_in', format: (v) => v ? `${v} in` : 'N/A', category: 'physical' },
  { label: 'Balance (pts)', key: 'balance_pts', format: (v) => v ? `${v > 0 ? '+' : ''}${v} pts` : 'N/A', category: 'physical' },
  { label: 'Swingweight', key: 'swingweight', format: (v) => v?.toString() || 'N/A', category: 'physical' },
  { label: 'Flex Rating', key: 'flex', format: (v) => v?.toString() || 'N/A', category: 'physical' },
  { label: 'String Pattern', key: 'string_pattern', category: 'physical' },
  { label: 'Construction', key: 'construction', category: 'physical' },

  // Performance Ratings
  { label: 'Power', key: 'power_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Control', key: 'control_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Comfort', key: 'comfort_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Maneuverability', key: 'maneuverability_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Stability', key: 'stability_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Serves', key: 'serves_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Returns', key: 'returns_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Groundstrokes', key: 'groundstrokes_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Volleys', key: 'volleys_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Touch/Feel', key: 'touch_feel_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Overall', key: 'overall_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
];

export function ComparisonTable({ racquets, className = '' }: ComparisonTableProps) {
  if (racquets.length === 0) {
    return (
      <div className={`text-center py-8 text-gray-500 ${className}`}>
        No racquets selected for comparison
      </div>
    );
  }

  const renderValue = (racquet: Racquet, row: ComparisonRow) => {
    const value = racquet[row.key];
    if (row.format) {
      return row.format(value);
    }
    return value?.toString() || 'N/A';
  };

  const getBestValue = (row: ComparisonRow) => {
    if (row.category !== 'performance') return null;

    const values = racquets
      .map(r => r[row.key] as number)
      .filter(v => v !== undefined);

    if (values.length === 0) return null;
    return Math.max(...values);
  };

  const isHighlighted = (racquet: Racquet, row: ComparisonRow) => {
    if (row.category !== 'performance') return false;

    const value = racquet[row.key] as number;
    const bestValue = getBestValue(row);

    return value !== undefined && bestValue !== null && Math.abs(value - bestValue) < 0.1;
  };

  const categoryLabels = {
    basic: 'Basic Information',
    physical: 'Physical Specifications',
    performance: 'Performance Ratings'
  };

  return (
    <div className={`overflow-x-auto ${className}`}>
      <table className="w-full border-collapse bg-white rounded-lg shadow-sm">
        <thead>
          <tr className="bg-gray-50">
            <th className="text-left p-4 font-medium text-gray-700 border-b">
              Specification
            </th>
            {racquets.map((racquet) => (
              <th
                key={racquet.id}
                className="text-left p-4 font-medium text-gray-700 border-b min-w-[200px]"
              >
                <div className="flex flex-col">
                  <span className="font-semibold">{racquet.brand}</span>
                  <span className="text-sm text-gray-500">{racquet.model}</span>
                </div>
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {Object.entries(categoryLabels).map(([category, label]) => (
            <React.Fragment key={category}>
              <tr className="bg-gray-100">
                <td
                  colSpan={racquets.length + 1}
                  className="p-3 font-semibold text-gray-700 text-sm uppercase tracking-wide"
                >
                  {label}
                </td>
              </tr>
              {COMPARISON_ROWS.filter(row => row.category === category).map((row) => (
                <tr key={row.key} className="hover:bg-gray-50">
                  <td className="p-4 font-medium text-gray-700 border-b">
                    {row.label}
                  </td>
                  {racquets.map((racquet) => (
                    <td
                      key={racquet.id}
                      className={`p-4 border-b ${
                        isHighlighted(racquet, row)
                          ? 'bg-green-50 text-green-800 font-semibold'
                          : 'text-gray-600'
                      }`}
                    >
                      {renderValue(racquet, row)}
                    </td>
                  ))}
                </tr>
              ))}
            </React.Fragment>
          ))}
        </tbody>
      </table>

      <div className="mt-4 text-sm text-gray-500 flex items-center gap-2">
        <div className="w-4 h-4 bg-green-50 border border-green-200 rounded"></div>
        <span>Highest performance rating in category</span>
      </div>
    </div>
  );
}

