input.content:
'use client';

import React, { useState } from 'react';
import { Button } from '../ui/Button';
import { Card } from '../ui/Card';
import { RadarChart } from './RadarChart';
import { ComparisonTable } from './ComparisonTable';
import { useRacquetComparison } from '../../lib/hooks/useRacquetComparison';

interface RacquetComparisonProps {
  className?: string;
}

type ViewMode = 'chart' | 'table' | 'both';

export function RacquetComparison({ className = '' }: RacquetComparisonProps) {
  const {
    selectedRacquets,
    isComparing,
    maxComparisons,
    clearComparison,
    toggleComparison,
    removeRacquet,
    exportComparison,
    comparisonData
  } = useRacquetComparison();

  const [viewMode, setViewMode] = useState<ViewMode>('both');

  if (!isComparing) return null;

  if (selectedRacquets.length === 0) {
    return (
      <Card className={`p-6 ${className}`}>
        <div className="text-center">
          <h3 className="text-lg font-semibold text-gray-700 mb-2">
            No Racquets Selected
          </h3>
          <p className="text-gray-500 mb-4">
            Select up to {maxComparisons} racquets to compare their specifications and performance.
          </p>
          <Button onClick={toggleComparison} variant="outline">
            Close Comparison
          </Button>
        </div>
      </Card>
    );
  }

  return (
    <Card className={`p-6 ${className}`}>
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-6">
        <div>
          <h3 className="text-lg font-semibold text-gray-800">
            Racquet Comparison
          </h3>
          <p className="text-sm text-gray-500">
            {selectedRacquets.length} of {maxComparisons} racquets selected
          </p>
        </div>

        <div className="flex flex-wrap gap-2">
          {/* View Mode Toggle */}
          <div className="flex border border-gray-300 rounded-lg overflow-hidden">
            <button
              onClick={() => setViewMode('chart')}
              className={`px-3 py-1 text-sm ${
                viewMode === 'chart'
                  ? 'bg-blue-500 text-white'
                  : 'bg-white text-gray-700 hover:bg-gray-50'
              }`}
            >
              Chart
            </button>
            <button
              onClick={() => setViewMode('table')}
              className={`px-3 py-1 text-sm ${
                viewMode === 'table'
                  ? 'bg-blue-500 text-white'
                  : 'bg-white text-gray-700 hover:bg-gray-50'
              }`}
            >
              Table
            </button>
            <button
              onClick={() => setViewMode('both')}
              className={`px-3 py-1 text-sm ${
                viewMode === 'both'
                  ? 'bg-blue-500 text-white'
                  : 'bg-white text-gray-700 hover:bg-gray-50'
              }`}
            >
              Both
            </button>
          </div>

          {/* Action Buttons */}
          <Button
            onClick={exportComparison}
            variant="outline"
            size="sm"
            disabled={selectedRacquets.length === 0}
          >
            Export CSV
          </Button>
          <Button
            onClick={clearComparison}
            variant="outline"
            size="sm"
          >
            Clear All
          </Button>
          <Button
            onClick={toggleComparison}
            variant="outline"
            size="sm"
          >
            Close
          </Button>
        </div>
      </div>

      {/* Selected Racquets */}
      <div className="mb-6">
        <h4 className="text-sm font-medium text-gray-700 mb-3">Selected Racquets</h4>
        <div className="flex flex-wrap gap-2">
          {selectedRacquets.map((racquet) => (
            <div
              key={racquet.id}
              className="flex items-center gap-2 bg-blue-50 text-blue-700 px-3 py-1 rounded-full text-sm"
            >
              <span>{racquet.brand} {racquet.model}</span>
              <button
                onClick={() => removeRacquet(racquet.id)}
                className="text-blue-500 hover:text-blue-700 ml-1"
              >
                ×
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Performance Analysis */}
      {comparisonData.categories.length > 0 && (
        <div className="mb-6">
          <h4 className="text-sm font-medium text-gray-700 mb-3">Performance Analysis</h4>
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <div className="bg-gray-50 p-4 rounded-lg">
              <h5 className="font-medium text-gray-700 mb-2">Trade-offs</h5>
              <div className="space-y-2 text-sm">
                {selectedRacquets.map((racquet, index) => {
                  const data = comparisonData.normalizedData[index];
                  const strengths = comparisonData.categories.filter(
                    cat => data.values[cat] > 0.8
                  );
                  const weaknesses = comparisonData.categories.filter(
                    cat => data.values[cat] < 0.3
                  );

                  return (
                    <div key={racquet.id} className="border-b border-gray-200 pb-2">
                      <div className="font-medium text-gray-700">
                        {racquet.brand} {racquet.model}
                      </div>
                      {strengths.length > 0 && (
                        <div className="text-green-600">
                          Strengths: {strengths.join(', ')}
                        </div>
                      )}
                      {weaknesses.length > 0 && (
                        <div className="text-red-600">
                          Weaknesses: {weaknesses.join(', ')}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>

            <div className="bg-gray-50 p-4 rounded-lg">
              <h5 className="font-medium text-gray-700 mb-2">Best In Class</h5>
              <div className="space-y-2 text-sm">
                {comparisonData.categories.map((category) => {
                  const maxValue = comparisonData.maxValues[category];
                  const bestRacquet = selectedRacquets.find(racquet => {
                    const avgKey = `${category.toLowerCase().replace(/\//g, '_')}_avg` as keyof typeof racquet;
                    return Math.abs((racquet[avgKey] as number) - maxValue) < 0.1;
                  });

                  return bestRacquet ? (
                    <div key={category} className="flex justify-between">
                      <span className="text-gray-600">{category}:</span>
                      <span className="font-medium">
                        {bestRacquet.brand} {bestRacquet.model}
                      </span>
                    </div>
                  ) : null;
                })}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Comparison Views */}
      <div className="space-y-8">
        {(viewMode === 'chart' || viewMode === 'both') && comparisonData.categories.length > 0 && (
          <div>
            <h4 className="text-sm font-medium text-gray-700 mb-4">Performance Radar Chart</h4>
            <RadarChart
              racquets={selectedRacquets}
              categories={comparisonData.categories}
              normalizedData={comparisonData.normalizedData}
              className="flex justify-center"
            />
          </div>
        )}

        {(viewMode === 'table' || viewMode === 'both') && (
          <div>
