'use client';

import React, { useState, useMemo } from 'react';
import { ScatterPlot } from './ScatterPlot';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Select } from '@/components/ui/Select';
import { Racquet } from '@/lib/types';

interface RacquetData {
  id: string;
  model: string;
  brand: string;
  weight_oz: number;
  head_size_sq_in: number;
  swingweight: number;
  flex: number;
  power_avg: number;
  control_avg: number;
  maneuverability_avg: number;
  stability_avg: number;
  comfort_avg: number;
  touch_feel_avg: number;
  overall_avg: number;
}

interface RacquetVisualizationProps {
  racquets: RacquetData[];
  className?: string;
  onRacquetSelect?: (racquet: Racquet) => void;
  selectedRacquets?: Racquet[];
  canAddMore?: boolean;
}

type AxisOption = {
  value: keyof RacquetData;
  label: string;
  description: string;
};

const axisOptions: AxisOption[] = [
  { value: 'weight_oz', label: 'Weight (oz)', description: 'Racquet weight in ounces' },
  { value: 'head_size_sq_in', label: 'Head Size (sq in)', description: 'Head size in square inches' },
  { value: 'swingweight', label: 'Swingweight', description: 'Swingweight measurement' },
  { value: 'flex', label: 'Flex Rating', description: 'Stiffness rating' },
  { value: 'power_avg', label: 'Power Rating', description: 'Average power rating' },
  { value: 'control_avg', label: 'Control Rating', description: 'Average control rating' },
  { value: 'maneuverability_avg', label: 'Maneuverability', description: 'Average maneuverability rating' },
  { value: 'stability_avg', label: 'Stability', description: 'Average stability rating' },
  { value: 'comfort_avg', label: 'Comfort', description: 'Average comfort rating' },
  { value: 'touch_feel_avg', label: 'Touch & Feel', description: 'Average touch and feel rating' },
  { value: 'overall_avg', label: 'Overall Rating', description: 'Overall average rating' },
];

const presetViews = [
  {
    id: 'power-control',
    name: 'Power vs Control',
    description: 'Compare power and control characteristics',
    xAxis: 'power_avg' as keyof RacquetData,
    yAxis: 'control_avg' as keyof RacquetData,
  },
  {
    id: 'weight-maneuver',
    name: 'Weight vs Maneuverability',
    description: 'Explore weight and maneuverability relationship',
    xAxis: 'weight_oz' as keyof RacquetData,
    yAxis: 'maneuverability_avg' as keyof RacquetData,
  },
  {
    id: 'flex-comfort',
    name: 'Flex vs Comfort',
    description: 'Examine stiffness and comfort trade-offs',
    xAxis: 'flex' as keyof RacquetData,
    yAxis: 'comfort_avg' as keyof RacquetData,
  },
  {
    id: 'headsize-stability',
    name: 'Head Size vs Stability',
    description: 'Analyze head size and stability correlation',
    xAxis: 'head_size_sq_in' as keyof RacquetData,
    yAxis: 'stability_avg' as keyof RacquetData,
  },
];

export function RacquetVisualization({ 
  racquets, 
  className = '', 
  onRacquetSelect,
  selectedRacquets = [],
  canAddMore = true 
}: RacquetVisualizationProps) {
  const [xAxis, setXAxis] = useState<keyof RacquetData>('power_avg');
  const [yAxis, setYAxis] = useState<keyof RacquetData>('control_avg');
  const [selectedRacquet, setSelectedRacquet] = useState<string | null>(null);

  // Handle racquet selection for comparison
  const handleRacquetClick = (point: { id: string }) => {
    if (onRacquetSelect) {
      const racquet = racquets.find(r => r.id === point.id);
      if (racquet) {
        // Convert RacquetData to Racquet type
        const racquetForComparison: Racquet = {
          ...racquet,
          code: racquet.id, // Use id as code if no code field
          length: '',
          head_size: racquet.head_size_sq_in?.toString() || '',
          weight: racquet.weight_oz?.toString() || '',
          balance: '',
          construction: '',
          material: '',
          string_pattern: '',
          length_in: undefined,
          balance_in: undefined,
          balance_pts: undefined,
        };
        onRacquetSelect(racquetForComparison);
      }
    }
    setSelectedRacquet(point.id);
  };

  // Check if a racquet is selected for comparison
  const isRacquetSelected = (racquetId: string) => {
    return selectedRacquets.some(r => r.id === racquetId);
  };

  // Transform racquet data for scatter plot
  const scatterData = useMemo(() => {
    return racquets
      .filter(racquet => 
        racquet[xAxis] !== undefined && 
        racquet[xAxis] !== null &&
        racquet[yAxis] !== undefined && 
        racquet[yAxis] !== null
      )
      .map(racquet => ({
        id: racquet.id,
        model: racquet.model,
        brand: racquet.brand,
        x: Number(racquet[xAxis]),
        y: Number(racquet[yAxis]),
        size: selectedRacquet === racquet.id ? 10 : (isRacquetSelected(racquet.id) ? 8 : 6),
        color: isRacquetSelected(racquet.id) ? '#3b82f6' : undefined,
      }));
  }, [racquets, xAxis, yAxis, selectedRacquet, selectedRacquets, isRacquetSelected]);

  const handlePresetView = (preset: typeof presetViews[0]) => {
    setXAxis(preset.xAxis);
    setYAxis(preset.yAxis);
  };

  const getAxisLabel = (axis: keyof RacquetData) => {
    return axisOptions.find(option => option.value === axis)?.label || String(axis);
  };

  const getAxisDescription = (axis: keyof RacquetData) => {
    return axisOptions.find(option => option.value === axis)?.description || '';
  };

  return (
    <div className={`space-y-6 ${className}`}>
      {/* Controls */}
      <Card className="p-6">
        <div className="space-y-4">
          <div>
            <div className="flex items-center justify-between mb-3">
              <h3 className="text-lg font-semibold">Visualization Controls</h3>
              {onRacquetSelect && (
                <div className="text-sm text-gray-600">
                  Click points to add to comparison ({selectedRacquets.length}/4)
                </div>
              )}
            </div>
            <div className="grid md:grid-cols-4 gap-3">
              {presetViews.map(preset => (
                <Button
                  key={preset.id}
                  variant={xAxis === preset.xAxis && yAxis === preset.yAxis ? 'default' : 'outline'}
                  size="sm"
                  onClick={() => handlePresetView(preset)}
                  className="text-sm h-auto py-3 px-4 flex flex-col items-start"
                >
                  <span className="font-medium">{preset.name}</span>
                  <span className="text-xs opacity-70 mt-1">{preset.description}</span>
                </Button>
              ))}
            </div>
          </div>

          <div className="grid md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium mb-2">X-Axis</label>
              <Select
                value={xAxis}
                onValueChange={(value) => setXAxis(value as keyof RacquetData)}
              >
                {axisOptions.map(option => (
                  <option key={option.value} value={option.value}>
                    {option.label}
                  </option>
                ))}
              </Select>
              <p className="text-xs text-foreground-muted mt-1">
                {getAxisDescription(xAxis)}
              </p>
            </div>

            <div>
              <label className="block text-sm font-medium mb-2">Y-Axis</label>
              <Select
                value={yAxis}
                onValueChange={(value) => setYAxis(value as keyof RacquetData)}
              >
                {axisOptions.map(option => (
                  <option key={option.value} value={option.value}>
                    {option.label}
                  </option>
                ))}
              </Select>
              <p className="text-xs text-foreground-muted mt-1">
                {getAxisDescription(yAxis)}
              </p>
            </div>
          </div>
        </div>
      </Card>

      {/* Visualization */}
      <ScatterPlot
        data={scatterData}
        xLabel={getAxisLabel(xAxis)}
        yLabel={getAxisLabel(yAxis)}
        title={`${getAxisLabel(xAxis)} vs ${getAxisLabel(yAxis)}`}
        onPointHover={(_point) => {
          // Could add hover effects here
        }}
        onPointClick={handleRacquetClick}
        className="min-h-[600px]"
      />

      {/* Selected Racquet Info */}
      {selectedRacquet && (
        <Card className="p-6">
          {(() => {
            const racquet = racquets.find(r => r.id === selectedRacquet);
            if (!racquet) return null;

            return (
              <div>
                <div className="flex items-center justify-between mb-4">
                  <h3 className="text-lg font-semibold">Selected Racquet</h3>
                  {onRacquetSelect && (
                    <div className="flex items-center gap-2">
                      {isRacquetSelected(racquet.id) ? (
                        <span className="text-sm text-blue-600 font-medium">
                          ✓ Added to comparison
                        </span>
                      ) : (
                        <Button
                          size="sm"
                          onClick={() => handleRacquetClick({ id: racquet.id })}
                          disabled={!canAddMore}
                          className="text-sm"
                        >
                          {canAddMore ? 'Add to Compare' : 'Max Reached'}
                        </Button>
                      )}
                    </div>
                  )}
                </div>
                <div className="grid md:grid-cols-2 gap-6">
                  <div>
                    <h4 className="font-medium text-primary mb-2">{racquet.model}</h4>
                    <p className="text-sm text-foreground-muted mb-3">by {racquet.brand}</p>

                    <div className="space-y-2">
                      <div className="flex justify-between">
                        <span className="text-sm">Weight:</span>
                        <span className="text-sm font-medium">{racquet.weight_oz} oz</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Head Size:</span>
                        <span className="text-sm font-medium">{racquet.head_size_sq_in} sq in</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Swingweight:</span>
                        <span className="text-sm font-medium">{racquet.swingweight}</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Flex:</span>
                        <span className="text-sm font-medium">{racquet.flex}</span>
                      </div>
                    </div>
                  </div>

                  <div>
                    <h4 className="font-medium mb-3">Performance Ratings</h4>
                    <div className="space-y-2">
                      <div className="flex justify-between">
                        <span className="text-sm">Power:</span>
                        <span className="text-sm font-medium">{racquet.power_avg}/10</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Control:</span>
                        <span className="text-sm font-medium">{racquet.control_avg}/10</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Maneuverability:</span>
                        <span className="text-sm font-medium">{racquet.maneuverability_avg}/10</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Stability:</span>
                        <span className="text-sm font-medium">{racquet.stability_avg}/10</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Comfort:</span>
                        <span className="text-sm font-medium">{racquet.comfort_avg}/10</span>
                      </div>
                      <div className="flex justify-between">
                        <span className="text-sm">Touch & Feel:</span>
                        <span className="text-sm font-medium">{racquet.touch_feel_avg}/10</span>
                      </div>
                      <div className="flex justify-between border-t pt-2">
                        <span className="text-sm font-medium">Overall:</span>
                        <span className="text-sm font-bold text-primary">{racquet.overall_avg}/10</span>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })()}
        </Card>
      )}

      {/* Summary Stats */}
      <Card className="p-6">
        <h3 className="text-lg font-semibold mb-4">Dataset Summary</h3>
        <div className="grid md:grid-cols-4 gap-4">
          <div className="text-center">
            <div className="text-2xl font-bold text-primary">{racquets.length}</div>
            <div className="text-sm text-foreground-muted">Total Racquets</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-primary">
              {new Set(racquets.map(r => r.brand)).size}
            </div>
            <div className="text-sm text-foreground-muted">Brands</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-primary">
              {Math.round(racquets.reduce((sum, r) => sum + r.overall_avg, 0) / racquets.length * 10) / 10}
            </div>
            <div className="text-sm text-foreground-muted">Avg Overall Rating</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-primary">
              {Math.round(racquets.reduce((sum, r) => sum + r.weight_oz, 0) / racquets.length * 10) / 10}
            </div>
            <div className="text-sm text-foreground-muted">Avg Weight (oz)</div>
          </div>
        </div>
      </Card>
    </div>
  );
}

